import java.net.*; import java.io.*; public class TestSwiggy { public static void main(String[] args) throws Exception { HttpURLConnection conn = (HttpURLConnection) new URL("https://www.swiggy.com/dapi/restaurants/list/v5?lat=17.385044&lng=78.486671&is-seo-homepage-enabled=true&page_type=DESKTOP_WEB_LISTING").openConnection(); conn.setRequestProperty("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36"); conn.setRequestProperty("Accept", "application/json"); System.out.println(conn.getResponseCode()); if(conn.getResponseCode() == 200) { BufferedReader in = new BufferedReader(new InputStreamReader(conn.getInputStream())); String inputLine; while((inputLine = in.readLine()) != null) { System.out.println(inputLine.substring(0, Math.min(inputLine.length(), 100))); break; } in.close(); } } }